// ============================================================
// Enrich Throttle Queue
// ------------------------------------------------------------
// Sits in front of the "Centralized Scheduled Grant fetch -
// Enrich Description" webhook. Producers POST a batch of grants
// to /webhook/enrich-queue; this workflow unrolls them one at a
// time with a small delay between calls, so the Enrich runner
// isn't hit with parallel fan-out (that's what's been crashing
// the task runner and taking all in-flight calls with it).
//
// Pattern: recursive self-dispatch. Ack returns 202 immediately;
// the Code node POSTs the head item to ENRICH_URL, sleeps
// DELAY_MS, then POSTs the tail back to QUEUE_URL (this same
// webhook) as a brand-new execution. Each execution processes
// exactly one grant, so no single run approaches the
// N8N_RUNNERS_TASK_TIMEOUT ceiling.
//
// IMPORTANT: this is fire-and-forget. The Enrich webhook's
// response body is NOT returned to the original producer - it
// is only logged in the return payload of each Code node. For
// this queue to be useful, Enrich must either (a) write the
// enriched description back to Supabase itself, or (b) the
// producer must be OK not seeing the result inline.
//
// Expected input (webhook body):
//   { "grants": [ { id, title, funder_name, source_url, description }, ... ] }
// A plain array or a single grant object is also accepted.
// ============================================================

const DELAY_MS    = 300;
const TIMEOUT_MS  = 120000;
const MAX_RETRIES = 2;
const ENRICH_URL  = 'https://n8n.thebrownmine.com/webhook/enrich-grant-description';
const QUEUE_URL   = 'https://n8n.thebrownmine.com/webhook/enrich-queue';

const helpers = this.helpers;
const raw = $input.first().json;
const input = raw.body || raw;

let grants;
if (Array.isArray(input)) {
  grants = input;
} else if (Array.isArray(input.grants)) {
  grants = input.grants;
} else if (input && (input.id || input.grant_id || input.source_url || input.title)) {
  grants = [input];
} else {
  grants = [];
}

if (grants.length === 0) {
  return [{ json: { success: true, forwarded: 0 } }];
}

const head = grants[0];
const tail = grants.slice(1);

async function post(url, body, attempt) {
  attempt = attempt || 0;
  try {
    await helpers.httpRequest({
      method:  'POST',
      url:     url,
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify(body),
      timeout: TIMEOUT_MS,
    });
    return { ok: true };
  } catch (e) {
    const status = e.httpCode || e.statusCode || (e.response && e.response.status);
    const transient = status === 429 || (status >= 500 && status < 600) || !status;
    if (transient && attempt < MAX_RETRIES) {
      const backoff = Math.min(5000, 500 * Math.pow(2, attempt)) + Math.floor(Math.random() * 250);
      await new Promise(function (r) { setTimeout(r, backoff); });
      return post(url, body, attempt + 1);
    }
    return { ok: false, status: status, message: String(e.message || e).slice(0, 400) };
  }
}

const enrichResult = await post(ENRICH_URL, head);

if (tail.length > 0) {
  await new Promise(function (r) { setTimeout(r, DELAY_MS); });
  await post(QUEUE_URL, { grants: tail });
}

return [{
  json: {
    success:          true,
    forwardedGrantId: head && (head.id || head.grant_id || null),
    enrichResult:     enrichResult,
    remaining:        tail.length,
  },
}];
